import{_ as a,o as r,c as t,a3 as l}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"用户档案 (User Profiles)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/user-profiles.md","filePath":"user-guide/tools/llm-chat/agents/user-profiles.md","lastUpdated":1778244893000}'),o={name:"user-guide/tools/llm-chat/agents/user-profiles.md"};function i(s,e,n,d,h,u){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="用户档案-user-profiles" tabindex="-1">用户档案 (User Profiles) <a class="header-anchor" href="#用户档案-user-profiles" aria-label="Permalink to &quot;用户档案 (User Profiles)&quot;">​</a></h1><p>用户档案用于存储关于“你”（用户）的信息。通过将档案与 Agent 绑定，Agent 可以在对话中感知你的身份、偏好和背景，从而提供更具代入感的回复。</p><div><h2 id="_1-核心作用" tabindex="-1">1. 核心作用 <a class="header-anchor" href="#_1-核心作用" aria-label="Permalink to &quot;1. 核心作用&quot;">​</a></h2><ul><li><strong>身份注入</strong>: 自动将你的姓名、性别、年龄等基本信息注入提示词。</li><li><strong>背景感知</strong>: 存储你的职业、爱好、过往经历等长效背景。</li><li><strong>动态引用</strong>: 在提示词中通过 <code>{{user}}</code> 宏引用档案中的姓名，通过 <code>{{user_persona}}</code> 引用详细描述。</li></ul></div><h2 id="_2-管理档案" tabindex="-1">2. 管理档案 <a class="header-anchor" href="#_2-管理档案" aria-label="Permalink to &quot;2. 管理档案&quot;">​</a></h2><h3 id="创建与编辑" tabindex="-1">创建与编辑 <a class="header-anchor" href="#创建与编辑" aria-label="Permalink to &quot;创建与编辑&quot;">​</a></h3><ol><li>在 Agent 编辑器的「角色设定」面板中，点击 <strong>「关联用户档案」</strong>。</li><li>在弹出的对话框中，你可以创建多个不同的档案（如“工作模式”、“游戏模式”）。</li><li>填写详细的描述（Persona），描述你希望 Agent 如何看待你。</li></ol><h3 id="档案组件" tabindex="-1">档案组件 <a class="header-anchor" href="#档案组件" aria-label="Permalink to &quot;档案组件&quot;">​</a></h3><ul><li><strong>姓名</strong>: 你的显示名称。</li><li><strong>描述</strong>: 关于你的详细设定。</li><li><strong>头像</strong>: 支持图片或 Emoji。</li></ul><h2 id="_3-绑定策略" tabindex="-1">3. 绑定策略 <a class="header-anchor" href="#_3-绑定策略" aria-label="Permalink to &quot;3. 绑定策略&quot;">​</a></h2><p>每个 Agent 只能绑定一个活跃的用户档案。</p><ul><li><strong>全局默认</strong>: 你可以在系统设置中指定一个全局默认档案。</li><li><strong>Agent 覆盖</strong>: 在 Agent 编辑器中指定的档案将覆盖全局设置。</li></ul><h2 id="_4-预览与调试" tabindex="-1">4. 预览与调试 <a class="header-anchor" href="#_4-预览与调试" aria-label="Permalink to &quot;4. 预览与调试&quot;">​</a></h2><p>你可以通过<a href="./../context-pipeline/analyzer">上下文分析器</a>查看用户档案是如何被组装进最终发送给 LLM 的提示词中的。通常，档案内容会作为系统提示词的一部分或特定的 <code>user</code> 角色消息注入。</p><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./editor-guide">Agent 基础设定</a></li><li><a href="./parameters">参数配置与注入策略</a></li></ul>',16)])])}const _=a(o,[["render",i]]);export{g as __pageData,_ as default};
